// ==== CONFIGURAÇÃO ====
const SHEET_ID = '1Nvv7MVhjX3QGeuqUXgpIkEfyJFK-TGqPykJIIlvBLJI';
const ABA_ACEITES = 'Aceites';
const EMAIL_ORGANIZACAO = 'eitaloversrodfestfolia@gmail.com';
const PRAZO_LIMITE = new Date('2026-07-17T23:59:00-03:00');
const ARQUIVO_HTML_TICKET = 'termo'; // rodfest_termo_de_embarque.html
const NOME_REMETENTE = 'RodFest Folia 2026'; // nome exibido no lugar do e-mail cru na caixa de entrada de quem recebe

// Brasão do RodFest (mesmo PNG do ticket), 154x180, reduzido pra caber num e-mail sem pesar.
// Gerado uma vez a partir do <img class="badge-crest"> de termo.html — se o brasão mudar, regenerar este base64.
const BRASAO_PNG_BASE64 = '';

// ==== doGet: serve o ticket na URL /exec ====
function doGet(e) {
  return HtmlService.createHtmlOutputFromFile(ARQUIVO_HTML_TICKET)
    .setTitle('RodFest Folia | Termo de Embarque')
    .addMetaTag('viewport', 'width=device-width, initial-scale=1');
}

// ==== doPost: recebe o aceite do formulário ====
function doPost(e) {
  try {
    const dados = JSON.parse(e.postData.contents);

    if (new Date() > PRAZO_LIMITE) {
      return responderJson({ ok: false, motivo: 'prazo encerrado' });
    }
    if (!dados.nome || !dados.telefone || !dados.email || dados.declarou_maior_idade !== true || dados.aceitou_termos !== true) {
      return responderJson({ ok: false, motivo: 'dados incompletos' });
    }

    const sheet = getAbaAceites();
    const telefoneNormalizado = normalizarTelefone(dados.telefone);
    const linhaExistente = encontrarLinhaPorTelefone(sheet, telefoneNormalizado);

    const linha = [
      new Date(),
      dados.nome,
      dados.telefone,
      dados.email,
      dados.declarou_maior_idade,
      dados.aceitou_termos,
      dados.termo_versao,
      dados.protocolo,
      dados.user_agent || ''
    ];

    const foiAtualizacao = linhaExistente > 0;
    if (foiAtualizacao) {
      sheet.getRange(linhaExistente, 1, 1, linha.length).setValues([linha]);
    } else {
      sheet.appendRow(linha);
    }

    enviarEmailConfirmacao(dados);
    notificarOrganizacao(dados, foiAtualizacao);

    return responderJson({ ok: true, protocolo: dados.protocolo });

  } catch (erro) {
    return responderJson({ ok: false, motivo: 'erro interno', detalhe: String(erro) });
  }
}

function responderJson(obj) {
  return ContentService.createTextOutput(JSON.stringify(obj))
    .setMimeType(ContentService.MimeType.JSON);
}
// ==== Planilha ====
function getAbaAceites() {
  const planilha = SpreadsheetApp.openById(SHEET_ID);
  let aba = planilha.getSheetByName(ABA_ACEITES);
  if (!aba) {
    aba = planilha.insertSheet(ABA_ACEITES);
    aba.appendRow([
      'timestamp', 'nome', 'telefone', 'email',
      'declarou_maior_idade', 'aceitou_termos', 'termo_versao',
      'protocolo', 'user_agent'
    ]);
  }
  return aba;
}

function normalizarTelefone(tel) {
  return String(tel).replace(/\D/g, ''); // mantém só os números, ignora formatação
}

function encontrarLinhaPorTelefone(sheet, telefoneNormalizado) {
  const dados = sheet.getDataRange().getValues();
  for (let i = 1; i < dados.length; i++) { // pula o cabeçalho
    if (normalizarTelefone(dados[i][2]) === telefoneNormalizado) { // coluna C = telefone
      return i + 1; // linha real na planilha (1-indexed)
    }
  }
  return -1;
}

// ==== E-mails (com a identidade visual do ticket) ====

// Texto oficial das 4 cláusulas, igual ao de termo.html — se o termo mudar de versão, atualizar aqui também.
// Emoji fica separado do nome porque o htmlBody do GmailApp precisa dele como entidade numérica (ver emojiParaEntidadeHtml_).
const CLAUSULAS_TERMO = [
  { emoji: '📸', nome: 'Uso de imagem', texto: 'Vamos registrar fotos e vídeos da festa para postar no @eitalovers e redes sociais. Se não quiser aparecer, avise a produção na entrada. Fora isso, ao confirmar presença você autoriza o uso da sua imagem nesses registros.' },
  { emoji: '🏡', nome: 'Danos à propriedade', texto: 'A chácara, a piscina, o campo e os equipamentos são de terceiros. Cada convidado responde por qualquer dano que causar por mau uso ou imprudência. Acidentes do uso normal do espaço são risco que você assume ao participar.' },
  { emoji: '🎒', nome: 'Itens pessoais', texto: 'Não tem serviço de guarda-volumes no evento. A organização não se responsabiliza por perda, troca ou furto de celular, carteira, roupas e outros itens pessoais. Evite deixar objetos de valor sem alguém de confiança por perto.' },
  { emoji: '💳', nome: 'Reembolso e cancelamento', texto: 'Você pode cancelar e pedir reembolso integral em até 7 dias corridos após a compra (Art. 49 do CDC), desde que solicite até 48 horas antes do início da festa. Estamos na reta final antes do evento e a organização já reservou comida, bebida e estrutura com base nos confirmados — por isso, a partir de agora não é mais possível cancelar ou pedir reembolso, mesmo que ainda esteja dentro dos 7 dias corridos da compra. Se o evento for cancelado pela organização, o reembolso integral continua garantido.' }
];

// ponytail: GmailApp corrompe emoji fora do BMP (📸🏡🎒💳) dentro de htmlBody quando
// a mensagem também tem inlineImages — bug conhecido do GmailApp, não do nosso texto
// (a fonte em Código.js está em UTF-8 correto). Convertendo pra entidade numérica
// (&#128248;) o Gmail renderiza o emoji igual, sem passar pelo trecho com bug.
function emojiParaEntidadeHtml_(emoji) {
  return Array.from(emoji).map(ch => `&#${ch.codePointAt(0)};`).join('');
}

function getBrasaoBlob_() {
  return Utilities.newBlob(Utilities.base64Decode(BRASAO_PNG_BASE64), 'image/png', 'brasao.png');
}

function formatarDataHora_(iso) {
  return Utilities.formatDate(new Date(iso), 'America/Sao_Paulo', "dd/MM/yyyy HH:mm");
}

// Moldura visual (brasão + cores do ticket) reaproveitada pelos dois e-mails.
function envolverEmailHtml_(badge, corpoHtml) {
  return `<div style="background:#0B4020;padding:28px 12px;font-family:Arial,Helvetica,sans-serif;">
  <div style="max-width:480px;margin:0 auto;background:#FFFDF6;border-radius:14px;overflow:hidden;border:1px solid #EDE6D2;">
    <div style="background:repeating-linear-gradient(45deg,#1C3F94 0 10px,#FFD400 10px 20px);padding:3px;">
      <div style="background:#189A46;padding:22px 16px;text-align:center;">
        <img src="cid:brasao" width="70" alt="RodFest" style="display:block;margin:0 auto 10px;">
        <div style="color:#FFD400;font-weight:800;letter-spacing:.12em;font-size:11px;">THE WORLD CUP EXPERIENCE</div>
        <div style="color:#fff;font-size:22px;font-weight:800;margin-top:4px;">RODFEST FOLIA</div>
        <div style="display:inline-block;margin-top:10px;background:#FFD400;color:#0B4020;font-weight:800;font-size:12px;padding:5px 14px;border-radius:999px;">${badge}</div>
      </div>
    </div>
    <div style="padding:22px 20px;color:#12210F;font-size:14px;line-height:1.55;">${corpoHtml}</div>
    <div style="background:#0B4020;color:#CFE3D3;text-align:center;font-size:11px;padding:14px;line-height:1.5;">RodFest Folia · 18/07/2026 · 09:30 às 22:00<br>Dúvidas? Fala com a produção no grupo do WhatsApp.</div>
  </div>
</div>`;
}

function clausulasHtml_() {
  return CLAUSULAS_TERMO.map(c => `<div style="margin:0 0 10px;padding:10px 12px;background:#FFFEFA;border:1px solid #EDE6D2;border-radius:8px;">
    <div style="font-weight:800;color:#0B4020;margin-bottom:4px;font-size:13px;">${emojiParaEntidadeHtml_(c.emoji)} ${c.nome}</div>
    <div style="font-size:13px;color:#3A3A32;">${c.texto}</div>
  </div>`).join('');
}

function enviarEmailConfirmacao(dados) {
  const primeiroNome = dados.nome.split(' ')[0];

  const corpoTexto = `Oi ${primeiroNome}!

Sua presença no RodFest Folia está confirmada. Protocolo: ${dados.protocolo}

Termo aceito na íntegra (${dados.termo_versao}):
${CLAUSULAS_TERMO.map(c => `${c.nome}\n${c.texto}`).join('\n\n')}

Você declarou ter 18 anos ou mais e aceitou os termos acima em ${formatarDataHora_(dados.aceito_em)}.

Data: 18/07/2026, das 09:30 às 22:00.
Qualquer dúvida, chama no grupo do WhatsApp.`;

  const corpoHtml = `<p style="margin:0 0 14px;">Oi <strong>${primeiroNome}</strong>! Sua presença no RodFest Folia está <strong style="color:#189A46;">confirmada</strong>.</p>
    <div style="background:#EDE6D2;border-radius:8px;padding:10px 14px;text-align:center;font-family:monospace;font-size:15px;color:#0B4020;letter-spacing:.05em;margin:0 0 18px;">${dados.protocolo}</div>
    <p style="margin:0 0 14px;"><strong>Termo aceito na íntegra (${dados.termo_versao}):</strong></p>
    ${clausulasHtml_()}
    <p style="margin:14px 0 0;font-size:12px;color:#7A7160;">Você declarou ter 18 anos ou mais e aceitou os termos acima em ${formatarDataHora_(dados.aceito_em)}.</p>`;

  GmailApp.sendEmail(dados.email, 'RodFest Folia: confirmação de presença', corpoTexto, {
    name: NOME_REMETENTE,
    htmlBody: envolverEmailHtml_('PRESENÇA CONFIRMADA', corpoHtml),
    inlineImages: { brasao: getBrasaoBlob_() }
  });
}

function notificarOrganizacao(dados, foiAtualizacao) {
  const linhas = [
    ['Nome', dados.nome],
    ['WhatsApp', dados.telefone],
    ['E-mail', dados.email],
    ['Protocolo', dados.protocolo],
    ['Aceito em', formatarDataHora_(dados.aceito_em)]
  ];

  const corpoTexto = `${foiAtualizacao ? 'Aceite atualizado' : 'Novo aceite registrado'}.

${linhas.map(([rotulo, valor]) => `${rotulo}: ${valor}`).join('\n')}`;

  const corpoHtml = `<p style="margin:0 0 14px;">${foiAtualizacao ? 'Aceite atualizado' : 'Novo aceite registrado'}.</p>
    <table style="width:100%;font-size:13px;border-collapse:collapse;">
      ${linhas.map(([rotulo, valor]) => `<tr><td style="padding:4px 10px 4px 0;color:#7A7160;white-space:nowrap;">${rotulo}</td><td style="padding:4px 0;font-weight:700;">${valor}</td></tr>`).join('')}
    </table>`;

  GmailApp.sendEmail(
    EMAIL_ORGANIZACAO,
    `RodFest: ${dados.nome} ${foiAtualizacao ? 'atualizou' : 'confirmou'} presença`,
    corpoTexto,
    {
      name: NOME_REMETENTE,
      htmlBody: envolverEmailHtml_(foiAtualizacao ? 'ACEITE ATUALIZADO' : 'NOVO ACEITE', corpoHtml),
      inlineImages: { brasao: getBrasaoBlob_() }
    }
  );
}

// ==== Painel de check-in ====
// Rode esta função UMA VEZ manualmente no editor do Apps Script
// (selecione "configurarAbaCheckin" no menu de funções e clique em Executar).
// Ela cria uma aba "Checkin" com nome, telefone e protocolo, fácil de buscar
// com Ctrl+F na entrada da chácara.
function configurarAbaCheckin() {
  const planilha = SpreadsheetApp.openById(SHEET_ID);
  let aba = planilha.getSheetByName('Checkin');
  if (!aba) aba = planilha.insertSheet('Checkin');
  aba.clear();
  aba.getRange('A1').setValue('Busque o telefone com Ctrl+F nesta aba (atualiza sozinha).');
  aba.getRange('A3').setFormula(
    `=QUERY(${ABA_ACEITES}!A2:H, "select Col2, Col3, Col8 where Col2 is not null order by Col2 label Col2 'Nome', Col3 'Telefone', Col8 'Protocolo'", 0)`
  );
}

/**
 * Self-check manual do template de e-mail: rode pelo editor do Apps Script
 * (selecionar "testeEmailHtml_" → Executar). Não envia e-mail nenhum, só
 * confere se o HTML monta certo e se o brasão embutido decodifica.
 */
function testeEmailHtml_() {
  const dadosFake = {
    nome: 'Fulano de Tal', telefone: '41999990000', email: 'fulano@example.com',
    termo_versao: 'v1.2', protocolo: 'RF-TESTE', aceito_em: new Date().toISOString()
  };

  const html = envolverEmailHtml_('PRESENÇA CONFIRMADA', `
    <div>${dadosFake.protocolo}</div>
    ${clausulasHtml_()}
  `);

  if (!html.includes('cid:brasao')) throw new Error('template sem referência ao brasão (cid:brasao)');
  if (!html.includes(dadosFake.protocolo)) throw new Error('protocolo não apareceu no HTML');
  CLAUSULAS_TERMO.forEach(c => {
    const entidade = emojiParaEntidadeHtml_(c.emoji);
    if (!html.includes(entidade) || !html.includes(c.nome) || !html.includes(c.texto)) {
      throw new Error('cláusula ausente ou com emoji cru (não convertido) no e-mail: ' + c.nome);
    }
    if (html.includes(c.emoji)) {
      throw new Error('emoji cru vazou pro HTML (deveria estar como entidade numérica): ' + c.nome);
    }
  });

  const blob = getBrasaoBlob_();
  if (blob.getBytes().length < 1000) throw new Error('BRASAO_PNG_BASE64 não decodificou um PNG válido');

  Logger.log('testeEmailHtml_ ok: template e brasão certos.');
}
